// RAW MESSY DATA
const users = [
  { user_id: 101, age: 25, city: 'Pune', annual_income: 50000 },
  { user_id: 102, age: null, city: 'Mumbai', annual_income: 60000 },
  { user_id: 103, age: 32, city: 'Pune', annual_income: 120000 },
  { user_id: 104, age: 150, city: 'Delhi', annual_income: 9999999 }
];

const transactions = [
  { user_id: 101, amount: 1200 }, { user_id: 101, amount: 800 },
  { user_id: 102, amount: 1500 },
  { user_id: 103, amount: 300 }, { user_id: 103, amount: 450 }, { user_id: 103, amount: 600 }
];

return [{ json: { users, transactions } }];

let data = $input.first().json;
let users = data.users || [];

// CLEANING
users.forEach(u => {
  if (u.age === null || u.age === undefined) u.age = 28;
  if (u.age > 99) u.age = 99;
});

// Remove extreme income outliers
users = users.filter(u => u.annual_income < 1000000);

data.users = users;
return [{ json: data }];

let data = $input.first().json;
let users = data.users || [];

// TRANSFORM & ENCODE
users.forEach(u => {
  u.scaled_income = u.annual_income / 100000;

  u.city_Pune = u.city === 'Pune' ? 1 : 0;
  u.city_Mumbai = u.city === 'Mumbai' ? 1 : 0;
  u.city_Delhi = u.city === 'Delhi' ? 1 : 0;

  delete u.city;
  delete u.annual_income;
});

return [{ json: data }];

let data = $input.first().json;
let users = data.users || [];
let txs = data.transactions || [];

// AGGREGATE & SELECT
users.forEach(u => {
  let userTxs = txs.filter(t => t.user_id === u.user_id);
  let total = userTxs.reduce((sum, t) => sum + t.amount, 0);
  u.avg_spend = userTxs.length ? total / userTxs.length : 0;

  delete u.user_id;
});

return users.map(u => ({ json: u }));
